import React from 'react';

const PreviewDoc = React.forwardRef(function PreviewDoc(
  { tpl, studentName, uid, section, worksheetNo, datePerf, sectionContent },
  ref
) {
  return (
    <div
      ref={ref}
      id="pdf-preview-root"
      style={{
        background: '#ffffff',
        color: '#111111',
        fontFamily: `'${tpl.bodyFont}', sans-serif`,
        fontSize: `${tpl.fontSize}pt`,
        lineHeight: tpl.spacing,
        textAlign: tpl.align,
        padding: '40px 52px',
        width: '794px',
        minHeight: '1123px',
        boxSizing: 'border-box',
        margin: '0 auto',
      }}
    >
      {/* HEADER */}
      <div style={{
        textAlign: 'center',
        paddingBottom: 14,
        marginBottom: 18,
      }}>
        <div style={{
          fontFamily: `'${tpl.headingFont}', serif`,
          fontSize: `${tpl.fontSize + 8}pt`,
          fontWeight: 700,
        }}>
          {tpl.university || 'University Name'}
        </div>

        <div style={{
          fontSize: `${tpl.fontSize - 1}pt`,
          color: '#555',
          marginTop: 3,
          fontStyle: 'italic'
        }}>
          Discover. Learn. Empower.
        </div>

        <div style={{
          fontFamily: `'${tpl.headingFont}', serif`,
          fontSize: `${tpl.fontSize + 5}pt`,
          fontWeight: 700,
          marginTop: 12,
        }}>
          Worksheet {worksheetNo}
        </div>
      </div>

      {/* STUDENT INFO */}
      <table style={{ width: '100%', marginBottom: 20 }}>
        <tbody>
          {[
            [['Student Name', studentName], ['UID', uid]],
            [['Branch', tpl.branch],        ['Section/Group', section]],
            [['Semester', tpl.semester],    ['Date of Performance', datePerf]],
            [['Subject Name', tpl.subject], ['Subject Code', tpl.subjectCode]],
          ].map((row, ri) => (
            <tr key={ri}>
              {row.map(([k, v]) => (
                <td key={k} style={{ padding: '3px 0', width: '50%' }}>
                  <strong>{k}:</strong> {v}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      {/* SECTIONS */}
      {tpl.sections.map((sec, i) => (
        <div key={sec} style={{ marginBottom: 20 }}>
          <div style={{
            fontFamily: `'${tpl.headingFont}', serif`,
            fontSize: `${tpl.fontSize + 1}pt`,
            fontWeight: 700,
            marginBottom: 6,
          }}>
            {i + 1}. {sec}:
          </div>

          <div style={{
            whiteSpace: 'pre-wrap',
            paddingLeft: 4,
            fontFamily: sec.toLowerCase().includes('code') ? 'monospace' : 'inherit',
            background: sec.toLowerCase().includes('code') ? '#f5f5f5' : 'transparent',
            padding: sec.toLowerCase().includes('code') ? '10px 12px' : '0 4px',
            borderRadius: sec.toLowerCase().includes('code') ? 4 : 0,
          }}>
            {sectionContent[sec] || (
              <span style={{ color: '#aaa', fontStyle: 'italic' }}>
                (no content)
              </span>
            )}
          </div>
        </div>
      ))}
    </div>
  );
});

export default PreviewDoc;
